import { FlatList } from 'react-native';
import React from 'react';

const ITEM_HEIGHT = 60;

const MemoizedItem = React.memo(({ item }) => (
  <View style={{ height: ITEM_HEIGHT }}>
    <Text>{item.title}</Text>
  </View>
));

<FlatList
  data={items}
  renderItem={({ item }) => <MemoizedItem item={item} />}
  keyExtractor={item => item.id}
  getItemLayout={(_, index) => ({
    length: ITEM_HEIGHT,
    offset: ITEM_HEIGHT * index,
    index,
  })}
  windowSize={10}
  maxToRenderPerBatch={10}
  removeClippedSubviews={true}
/>

// BEFORE (wrong - layout property with native driver)
Animated.timing(animValue, {
  toValue: 100,
  useNativeDriver: true,  // can't animate 'width' natively
}).start();
// style={{ width: animValue }}

// AFTER (correct - use transform instead)
Animated.timing(animValue, {
  toValue: 100,
  useNativeDriver: true,  // OK for transform
}).start();
// style={{ transform: [{ translateX: animValue }] }}

// Or use reanimated for layout animations:
import Animated, { useSharedValue, withTiming } from 'react-native-reanimated';

// babel.config.js - ensure preset is configured:
module.exports = {
  presets: ['module:@react-native/babel-preset'],
  plugins: [
    // Add any needed syntax plugins
    '@babel/plugin-proposal-optional-chaining',
  ],
};
